void seleccionarAsignaturas(int n, int C, vector<char> aprobadas, vector<int> prerrequisitos, vector<int> creditos, vector<int> costes) {
    // Inicializar variables para el coste mínimo
    int costeMinimo = INT_MAX;
    // Función recursiva para explorar combinaciones
    function<void(int, int, int)> backtrack = [&](int index, int creditosActuales, int costeActual) {
        // Comprobar si se cumplen los créditos mínimos
        if (creditosActuales >= C) {
            costeMinimo = min(costeMinimo, costeActual);
            return;
        }
        // Explorar asignaturas
        for (int i = index; i < n; ++i) {
            // Comprobar prerrequisitos
            if (aprobadas[i] == 'N' && (prerrequisitos[i] == -1 || aprobadas[prerrequisitos[i]] == 'A')) {
                // Poda por coste
                if (costeActual + costes[i] < costeMinimo) {
                    // Marcar asignatura como seleccionada
                    aprobadas[i] = 'A';
                    backtrack(i + 1, creditosActuales + creditos[i], costeActual + costes[i]);
                    // Desmarcar asignatura
                    aprobadas[i] = 'N';
                }
            }
        }
    };
    // Llamar a la función recursiva
    backtrack(0, 0, 0);
    // Imprimir resultado
    if (costeMinimo == INT_MAX) {
        cout << "NO" << endl;
    } else {
        cout << costeMinimo << endl;
    }
}
